      "content": "// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const tasksStore = [];

module.exports = {
  createTask(projectId, task) {
    const newTask = {
      id: randomUUID(),
      projectId,
      ...task,
      status: 'todo',
    };
    tasksStore.push(newTask);
    return newTask;
  },

  getTasksByProjectId(projectId) {
    return tasksStore.filter(task => task.projectId === projectId);
  },

  updateTaskStatus(taskId, status) {
    const task = tasksStore.find(t => t.id === taskId);
    if (task && ['todo', 'done'].includes(status)) {
      task.status = status;
      return task;
    }
    return null;
  },

  getTasksByStatus(projectId, status) {
    return tasksStore.filter(task => task.projectId === projectId && task.status === status);
  },
};
